// Populates community dropdowns on Assign/Remove pages via AdminHelper/LoadCommunitiesList.
(function () {
    function populate(selector) {
        var $sel = $(selector);
        if (!$sel.length) return;
        $.getJSON('/AdminHelper/LoadCommunitiesList', function (items) {
            $sel.empty().append('<option value="">-- Select Community --</option>');
            $.each(items, function (_, item) {
                $sel.append($('<option>').val(item.Value).text(item.Text));
            });
            // For Remove pages: restore the previously POSTed community so the
            // list stays filtered after a form submit.
            var $stored = $('#EditModeCommunityID');
            if ($stored.length) {
                var id = $stored.text().trim();
                if (id && id !== '0') { $sel.val(id); }
            }
        });
    }
    $(document).ready(function () {
        populate('#CommunitiesDDL');
        populate('#communitydropdown');
    });
})();
